	`TMP=$(mktemp -d -t ddx-e2e-XXXXXX)`,
	`cp -R "${FIXTURE_DIR}/." "$TMP/"`,
	`(cd "${CLI_PKG_DIR}" && go build -o "$TMP/ddx" .)`,
	`cd "$TMP"`,
	`exec ./ddx server --tsnet=false --addr=127.0.0.1 --port=${PORT}`

